// ==================================================
//  components/Navbar.jsx
// ==================================================
import React, { useState } from 'react'
import { Link, useNavigate, useLocation } from 'react-router-dom'

export default function Navbar() {
  const navigate  = useNavigate()
  const location  = useLocation()
  const token     = localStorage.getItem('access_token')
  const [open, setOpen] = useState(false)

  const logout = () => {
    localStorage.removeItem('access_token')
    localStorage.removeItem('refresh_token')
    navigate('/login')
  }

  const isActive = (path) => location.pathname === path ? 'nav-active' : ''

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.logo}>
  <img src="/logo.png" alt="logo" style={{height: 40}} />
</Link>

      {/* روابط */}
      <div style={styles.links}>
        <Link to="/"        className={isActive('/')}        style={styles.link}>الرئيسية</Link>
        <Link to="/designs" className={isActive('/designs')} style={styles.link}>التصاميم</Link>
        {token && <Link to="/ai"      className={isActive('/ai')}      style={styles.link}>🤖 توليد تصميم</Link>}
        {token && <Link to="/orders"  className={isActive('/orders')}  style={styles.link}>طلباتي</Link>}
        {token && <Link to="/profile" className={isActive('/profile')} style={styles.link}>بروفايلي</Link>}
      </div>

      {/* أزرار */}
      <div style={styles.actions}>
        {token ? (
          <button onClick={logout} className="btn btn-outline" style={{padding:'8px 20px'}}>خروج</button>
        ) : (
          <>
            <Link to="/login"    className="btn btn-outline"  style={{padding:'8px 20px'}}>دخول</Link>
            <Link to="/register" className="btn btn-primary"  style={{padding:'8px 20px'}}>تسجيل</Link>
          </>
        )}
      </div>

      <style>{`
        .nav-active { color: #c9a84c !important; font-weight: 600; }
        @media(max-width:768px){ .nav-links { display: none; } }
      `}</style>
    </nav>
  )
}

const styles = {
  nav: {
    display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    padding: '16px 40px', background: '#fafafa',
    borderBottom: '1px solid #efefef', position: 'sticky', top: 0, zIndex: 100,
    boxShadow: '0 2px 12px rgba(0,0,0,0.05)'
  },
  logo: { fontFamily: "'Playfair Display', serif", fontSize: 22, fontWeight: 700, color: '#0a0a0a' },
  links: { display: 'flex', gap: 28 },
  link:  { fontSize: 15, color: '#444', transition: 'color 0.2s' },
  actions: { display: 'flex', gap: 10 }
}
